    import org.apache.commons.logging.LogFactory;
    import org.apache.commons.logging.Log;

    import sailpoint.tools.Message;
    import sailpoint.workflow.WorkflowContext;
    
    //#########################################
    // IIQ Loggers
    //#########################################
    private static String LOG_TRACE = "trace";
    private static String LOG_DEBUG = "debug";
    private static String LOG_INFO = "info";
    private static String LOG_WARN = "warn";
    private static String LOG_ERROR = "error";
    public void log(String name, String msg, String level) {
        Log log = LogFactory.getLog(name);
        if(LOG_INFO.equalsIgnoreCase(level)) {
            if(log.isInfoEnabled()) {
                log.info(msg);
            }
        }
        else if(LOG_WARN.equalsIgnoreCase(level)) {
            if(log.isWarnEnabled()) {
                log.warn(msg);
            }
        }
        else if(LOG_ERROR.equalsIgnoreCase(level)) {
            if(log.isErrorEnabled()) {
                log.error(msg);
            }
        }
        else if(LOG_TRACE.equalsIgnoreCase(level)) {
            if(log.isTraceEnabled()) {
                log.trace(msg);
            }
        }
        else {
            if(log.isDebugEnabled()) {
                log.debug(msg);
            }
        }
    }
    
    public void trace(String logName,String msg) {
        log(logName,msg,LOG_TRACE);
    }
    public void warn(String logName,String msg) {
        log(logName,msg,LOG_WARN);
    }
    public void error(String logName,String msg) {
        log(logName,msg,LOG_ERROR);
    }
    public void info(String logName,String msg) {
        log(logName,msg,LOG_INFO);
    }
    public void debug(String logName,String msg) {
        log(logName,msg,LOG_DEBUG);
    }
    public void error(String logName,String msg, Throwable t) {
        Log log = LogFactory.getLog(logName);
        log.error(msg,t);
    }
    public void error(Object logName,String msg, Throwable t) {
        Log log = LogFactory.getLog(logName.toString());
        log.error(msg,t);
    }
    //#########################################
    // Workflow Loggers
    //#########################################
    
    /**
     * Logs an Exception and appends error details to the workflow
     * @param wfcontext current workflow context
     * @param t Exception
     */
    public void handleWorkFlowException(WorkflowContext wfc, Throwable t) {
        String msg = "Exception in step "+wfc.getStep().getName();
        Object wfLogName = wfc.getWorkflow().get("logName");
        error(wfLogName,msg,t);
        wfc.getWorkflowCase().addException(t);
        wfc.getWorkflowCase().addMessage(Message.error(msg+". Exception was: "+t.getMessage()));
        wfc.getRootContext().getWorkflowCase().addException(t);
        wfc.getRootContext().getWorkflowCase().addMessage(Message.error(msg+" . Exception was: "+t.getMessage()));
    }
    
    /**
     * Convenience method to add a message to the workflow context
     */
    public void addMessage(WorkflowContext wfc, String msg) {
        wfc.getRootContext().getWorkflowCase().addMessage(msg);
    }
    
    /**
     * Convenience method to add a Warning to the workflow context
     */
    public void addWarning(WorkflowContext wfc, String msg) {
        wfc.getRootContext().getWorkflowCase().addMessage(new Message(Message.Type.Warn,msg,null));
    }
    
    /**
     * Convenience method to add a Error to the workflow context
     */
    public void addError(WorkflowContext wfc, String msg) {
        wfc.getRootContext().getWorkflowCase().addMessage(new Message(Message.Type.Error,msg,null));
    }
